+    #[test]
+    fn severity_colors_are_distinct() {
+        let colors = [
+            AlertSeverity::Info.color(),
+            AlertSeverity::Warn.color(),
+            AlertSeverity::Critical.color(),
+        ];
+        for (i, c) in colors.iter().enumerate() {
+            for (j, other) in colors.iter().enumerate() {
+                if i != j {
